import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"三尺剑非剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/三尺剑非剑.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/三尺剑非剑.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/三尺剑非剑.md"};function p(l,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"三尺剑非剑",tabindex:"-1"},[s("三尺剑非剑 "),e("a",{class:"header-anchor",href:"#三尺剑非剑","aria-label":'Permalink to "三尺剑非剑"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),o('<h1 id="三尺剑非剑-1" tabindex="-1">三尺剑非剑 <a class="header-anchor" href="#三尺剑非剑-1" aria-label="Permalink to &quot;三尺剑非剑&quot;">​</a></h1><p>三尺剑非剑<br> D+500<br> 魔幻本质<br> 容量为12的剑匣（箭袋）<br> 这是一个体积为3的古朴剑匣，其中被分为了12个剑槽，你可以自由指定此剑匣的木质与花纹。<br> 得道年来八百秋，不曾飞剑取人头。<br> 玉皇未有天符至， 且货乌金混世流。<br> 这个剑匣可以满足弓箭手使用炫酷飞剑的愿望。</p><p>三尺剑非剑：在战斗中，1回合1次，你可以花费1点任意通用能量在剑匣空置剑槽内生成1把武器伤害为3L，具有破甲1的剑，存在时间为1场景。<br> 剑的样式由你自行定义，如没有选择则固定为体积3的轻剑。</p><p>急！真的好急！：在战斗中，1回合1次，你可以花费2点任意通用能量在剑匣空置剑槽内生成8把武器伤害为0L的剑，你可以通过1次攻击，来一次性使用掉这些剑，这次攻击获得【连射】，【贯穿】【2破甲】。但由此效果生成的剑只能存在1轮时间。</p><p>别急，你先别急：当你在持有此剑匣的情况下，每经历1次影片，就会在下次进入影片时，剑匣的空置剑槽内会生成1把具有武器伤害3l，1破甲的剑，使用后消失。同时，持有此剑匣期间你的先攻增加2点。<br> 限制：<br> 无论如何，这种剑匣生成的剑只有基础的剑身与剑柄，因此，你只能用这种剑来代替箭矢，而无法如正常剑一样使用，同时你也无法将与剑相关的技艺/专长作用在这种剑上。仅只能作为一种箭矢使用。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
